import{j as e,e as s}from"./ui-DiPbLDQA.js";import{a as t,L as i}from"./vendor-DlOK_Mxb.js";import{C as n}from"./CtaPair-Bqshkc3c.js";function r(){return t.useEffect(()=>{document.title="The Hidden Cost of Bad Hiring Decisions | Thompson & Co Collective";const e=document.querySelector('meta[name="description"]');e&&e.setAttribute("content","Bad hires don't just cost money in salary and training. They cost time, momentum, and opportunity. Here's the full calculus of hiring mistakes and how to avoid them.");const s=document.createElement("script");return s.type="application/ld+json",s.text=JSON.stringify({"@context":"https://schema.org","@type":"Article",headline:"The Hidden Cost of Bad Hiring Decisions",description:"Bad hires don't just cost money in salary and training. They cost time, momentum, and opportunity. Here's the full calculus of hiring mistakes and how to avoid them.",author:{"@type":"Person",name:"Candice Thompson"},publisher:{"@type":"Organization",name:"Thompson & Co Collective",url:"https://thompsoncollective.co"},datePublished:"2024-04-02",url:"https://thompsoncollective.co/insights/hidden-cost-bad-hiring"}),s.id="article-schema",document.head.appendChild(s),()=>{const e=document.getElementById("article-schema");e&&document.head.removeChild(e)}},[]),e.jsx("main",{id:"main-content",className:"pt-24 pb-20",children:e.jsxs("article",{className:"max-w-4xl mx-auto px-4 sm:px-6 lg:px-8",children:[e.jsxs(i,{to:"/insights",className:"inline-flex items-center gap-2 text-[#117C92] hover:text-[#0D7377] transition-colors mb-8",children:[e.jsx(s,{className:"w-4 h-4"}),"Back to Insights"]}),e.jsxs("header",{className:"mb-12",children:[e.jsx("div",{className:"text-sm font-medium text-[#117C92] uppercase tracking-wide mb-4",children:"TALENT STRATEGY"}),e.jsx("h1",{className:"text-3xl md:text-4xl lg:text-5xl font-bold mb-6",style:{fontFamily:"var(--font-serif)",lineHeight:1.2,color:"#0A1220"},children:"The Hidden Cost of Bad Hiring Decisions"}),e.jsx("p",{className:"text-lg text-gray-600 leading-relaxed",children:"Bad hires don't just cost money in salary and training. They cost time, momentum, and opportunity. Here's the full calculus of hiring mistakes and how to avoid them."}),e.jsx("div",{className:"mt-6 text-sm text-gray-500",children:"By Candice Thompson • April 2, 2024"})]}),e.jsxs("div",{className:"prose prose-lg max-w-none",children:[e.jsx("p",{children:"Everyone knows bad hires are expensive. The standard calculation is 1.5x annual salary in direct costs. But that number dramatically understates the true impact. The real cost of a bad hiring decision goes far beyond dollars."}),e.jsx("p",{children:"After working with organizations that have made — and learned from — hiring mistakes, we've seen the full calculus. Here's what actually gets damaged when you bring the wrong person on board."}),e.jsx("h2",{children:"The Direct Costs (The Obvious Ones)"}),e.jsx("p",{children:"These are the costs that show up in budgets:"}),e.jsxs("ul",{children:[e.jsxs("li",{children:[e.jsx("strong",{children:"Salary and benefits:"})," 6-12 months of compensation"]}),e.jsxs("li",{children:[e.jsx("strong",{children:"Recruitment costs:"})," Agency fees, job board spend, internal time"]}),e.jsxs("li",{children:[e.jsx("strong",{children:"Onboarding and training:"})," Programs, materials, manager time"]}),e.jsxs("li",{children:[e.jsx("strong",{children:"Termination costs:"})," Severance, outplacement, legal fees"]})]}),e.jsx("h2",{children:"The Indirect Costs (The Expensive Ones)"}),e.jsx("p",{children:"These are the costs that destroy value:"}),e.jsx("h3",{children:"1. Team Productivity Loss"}),e.jsx("p",{children:"When someone isn't performing, their colleagues pick up the slack. High performers spend 20-30% of their time compensating for underperformers. That's lost innovation, delayed projects, and burned-out team members."}),e.jsx("h3",{children:"2. Manager Time and Energy"}),e.jsx("p",{children:"Managing poor performance takes enormous time. Coaching, documenting, performance reviews, disciplinary meetings. A single bad hire can consume 10+ hours per week of a manager's time."}),e.jsx("h3",{children:"3. Team Morale Damage"}),e.jsx("p",{children:"Bad hires create resentment. High performers see their extra effort go unrewarded. Good people start looking for other opportunities. The best teams we've worked with lost 2-3 high performers after a single bad hire."}),e.jsx("h3",{children:"4. Opportunity Cost"}),e.jsx("p",{children:"Every open role represents missed opportunities. A delayed hire means delayed projects, missed market opportunities, and slower growth. In fast-moving companies, this can be catastrophic."}),e.jsx("h2",{children:"The Long-Term Costs (The Permanent Ones)"}),e.jsx("p",{children:"Some damage doesn't heal:"}),e.jsx("h3",{children:"1. Reputation Damage"}),e.jsx("p",{children:"Bad hires leave and talk. They damage your employer brand on Glassdoor, LinkedIn, and in industry circles. This makes future hiring harder and more expensive."}),e.jsx("h3",{children:"2. Process Erosion"}),e.jsx("p",{children:"After a bad hire, teams become risk-averse. They slow down hiring processes, add more interviews, require more approvals. This makes it harder to hire good people quickly."}),e.jsx("h3",{children:"3. Cultural Scars"}),e.jsx("p",{children:'Trust in the hiring process erodes. Teams become cynical about new hires. The "we hire slow" mentality takes hold, and innovation slows.'}),e.jsx("h2",{children:"How to Avoid Bad Hires"}),e.jsx("p",{children:"The most effective organizations don't try to eliminate bad hires (that's impossible). They minimize them through better process:"}),e.jsx("h3",{children:"1. Define Success First"}),e.jsx("p",{children:"Before you start recruiting, define what success looks like in measurable terms. What will this person accomplish in 3 months, 6 months, 12 months?"}),e.jsx("h3",{children:"2. Assess for Capability, Not Just Experience"}),e.jsx("p",{children:"Past experience is a predictor, but not the only one. Assess for learning ability, problem-solving, and cultural fit. Use work samples and practical assessments."}),e.jsx("h3",{children:"3. Involve Multiple Perspectives"}),e.jsx("p",{children:"Don't let one person's enthusiasm drive the decision. Get input from peers, direct reports, and cross-functional colleagues."}),e.jsx("h3",{children:"4. Check References Thoroughly"}),e.jsx("p",{children:"Ask specific questions about past performance and challenges. Follow up on red flags. Most bad hires show warning signs that get ignored."}),e.jsx("h2",{children:"The Real ROI of Good Hiring"}),e.jsx("p",{children:"Good hires don't just avoid costs — they create value. The best people we've seen hired generate 5-10x their salary in value through innovation, leadership, and impact."}),e.jsx("p",{children:"Bad hiring decisions are expensive. But good ones are the highest-ROI investment most organizations make. The difference is in the process, not the luck."})]}),e.jsx("div",{className:"mt-16",children:e.jsx(n,{})})]})})}export{r as default};
